void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<ll>(n + 1);
	var b = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];
	fa(i, 1, n)cin >> b[i];
	ll x = 0, y = 0;
	fa(i, 1, n)x ^= a[i], y ^= b[i];

	ll tmp = x ^ y; // x y 差异
	if (tmp == 0) {
		cout << "Tie" << endl;
		return;
	}

	// 仅考虑 tmp 的最高位
	ll len = log2(tmp);
	ll ans = x >> len & 1;
	fa(i, 1, n) {
		if ((a[i] ^ b[i]) >> len & 1) {
			// 可通过 (a[i] ^ b[i]) 控制 tmp 最高位
			ans = i;
		}
	}
	if (ans & 1)cout << "Ajisai" << endl;
	else cout << "Mai" << endl;
	return;
}
